import React, { useState, useContext } from 'react'; 
import { Link } from 'react-router-dom'; 
import './Navbar.css';
import { AuthContext } from '../context/AuthContext'; // Importando o contexto de autenticação

const Navbar = () => {
  const { user } = useContext(AuthContext); // Acessando o contexto de autenticação
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [searchQuery, setSearchQuery] = useState(''); 

  const toggleDropdown = (dropdownName) => {
    if (activeDropdown === dropdownName) {
      setActiveDropdown(null); 
    } else {
      setActiveDropdown(dropdownName); 
    }
  };

  const handleSearch = () => {
    console.log('Buscando:', searchQuery);
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <div className="navbar-logo">Prometheus</div>
        <ul className="navbar-links">
          {user.permissions.includes('gestor') && ( // Exibir menu de Gestão apenas para usuários com permissão 'gestor'
            <li className="dropdown">
              <Link to="#" onClick={() => toggleDropdown('gestao')}>Gestão</Link>
              {activeDropdown === 'gestao' && (
                <ul className="dropdown-menu">
                  <li><Link to="/gestao/atendimento">Atendimento</Link></li>
                  <li><Link to="/gestao/pessoa">Pessoa</Link></li>
                  <li><Link to="/gestao/workflow">Workflow</Link></li>
                  <li><Link to="/gestao/timesheet">Timesheet</Link></li>
                  <li><Link to="/gestao/relatorios">Relatórios</Link></li>
                </ul>
              )}
            </li>
          )}

          {user.permissions.includes('colaborador') && ( // Exibir menu de Atividades apenas para usuários com permissão 'colaborador'
            <li className="dropdown">
              <Link to="#" onClick={() => toggleDropdown('atividades')}>Atividades</Link>
              {activeDropdown === 'atividades' && (
                <ul className="dropdown-menu">
                  <li><Link to="/atividades">Lista de Atividades</Link></li>
                  <li><Link to="/atividades/painel">Painel de Tarefas</Link></li>
                  <li><Link to="/atividades/kanban">Kanban</Link></li>
                  <li><Link to="/atividades/relatorios">Relatórios</Link></li>
                </ul>
              )}
            </li>
          )}

          {user.permissions.includes('gestor') && ( // Exibir menu de Processos apenas para usuários com permissão 'gestor'
            <li className="dropdown">
              <Link to="#" onClick={() => toggleDropdown('processos')}>Processos</Link>
              {activeDropdown === 'processos' && (
                <ul className="dropdown-menu">
                  <li><Link to="/processos">Listar Processos</Link></li>
                  <li><Link to="/processos/intimacoes">Intimações</Link></li>
                  <li><Link to="/processos/central-captura">Central de Captura</Link></li>
                  <li><Link to="/processos/andamentos">Andamentos Processuais</Link></li>
                  <li><Link to="/processos/relatorios">Relatórios</Link></li>
                </ul>
              )}
            </li>
          )}

          {user.permissions.includes('gestor') && ( // Exibir menu de Financeiro apenas para usuários com permissão 'gestor'
            <li className="dropdown">
              <Link to="#" onClick={() => toggleDropdown('financeiro')}>Financeiro</Link>
              {activeDropdown === 'financeiro' && (
                <ul className="dropdown-menu">
                  <li><Link to="/financeiro">Receitas e Despesas</Link></li>
                  <li><Link to="/financeiro/extrato">Extrato da Conta</Link></li>
                  <li><Link to="/financeiro/solicitacoes">Solicitações</Link></li>
                  <li><Link to="/financeiro/integracao-receitas">Integração de Receitas</Link></li>
                  <li><Link to="/financeiro/integracao-despesas">Integração de Despesas</Link></li>
                  <li><Link to="/financeiro/relatorios">Relatórios</Link></li>
                </ul>
              )}
            </li>
          )}

          {user.permissions.includes('gestor') && ( // Exibir menu de Documentos apenas para usuários com permissão 'gestor'
            <li className="dropdown">
              <Link to="#" onClick={() => toggleDropdown('documentos')}>Documentos</Link>
              {activeDropdown === 'documentos' && (
                <ul className="dropdown-menu">
                  <li><Link to="/documentos">Documentos</Link></li>
                  <li><Link to="/documentos/modelos">Modelos de Documentos</Link></li>
                </ul>
              )}
            </li>
          )}

          {user.permissions.includes('gestor') && ( // Exibir menu de Extensões apenas para usuários com permissão 'gestor'
            <li className="dropdown">
              <Link to="#" onClick={() => toggleDropdown('extensoes')}>Extensões</Link>
              {activeDropdown === 'extensoes' && (
                <ul className="dropdown-menu">
                  <li><Link to="/extensoes">Conexões</Link></li>
                  <li><Link to="/extensoes/relatorios">Relatórios</Link></li>
                </ul>
              )}
            </li>
          )}
        </ul>
      </div>
      <div className="navbar-right">
        <input
          type="text"
          placeholder="Buscar..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
        <button onClick={handleSearch}>Pesquisar</button>
      </div>
    </nav>
  );
};

export default Navbar;
